module up_down_counter (
    input wire reset_clk,
    input wire clr,
    input wire up_down,
    output reg [3:0] count
);

always @(posedge reset_clk) begin
    if (clr) begin
        count <= 4'b0000;
    end else if (up_down) begin
        count <= count + 1;
    end else begin
        count <= count - 1;
    end
end

endmodule
